// ── Helpers ──

export function findConstituency(slug: string): Constituency | undefined {
  return CONSTITUENCIES.find(c => c.slug === slug);
}

export function findByName(name: string): Constituency | undefined {
  const lower = name.toLowerCase();
  return CONSTITUENCIES.find(c => c.name.toLowerCase() === lower);
}

export function findByMemberId(id: number): Constituency | undefined {
  return CONSTITUENCIES.find(c => c.memberId === id);
}

export function getByRegion(region: string): Constituency[] {
  return CONSTITUENCIES.filter(c => c.region === region);
}

export function getByParty(party: string): Constituency[] {
  return CONSTITUENCIES.filter(c => c.party === party);
}

export const REGIONS = Array.from(new Set(CONSTITUENCIES.map(c => c.region))).sort();
export const PARTIES = Array.from(new Set(CONSTITUENCIES.map(c => c.party))).sort();
